qry:select.qry:xquery:
for $r in sql(' SELECT LIQ20_TOT_LIQ_PER.oi_tot_liq_per, LIQ97_PERSONAL_EMP.e_numero_legajo, LIQ97_PERSONAL_EMP.c_ubicacion, LIQ97_PERSONAL_EMP.d_ape_y_nom, ORG03_UBICACIONES.d_ubicacion, ORG18_CATEGORIAS.d_categoria, LIQ99_LIQUIDACION.c_empresa, ORG18_CONVENIOS.d_convenio, LIQ99_LIQUIDACION.c_liquidacion, LIQ99_LIQUIDACION.d_titulo, LIQ99_LIQUIDACION.e_periodo, LIQ99_LIQUIDACION.l_ajuste, LIQ01_TIPOS_LIQ.c_tipo_liq, LIQ01_TIPOS_LIQ.d_tipo_liq, ORG08_CS_COSTO.d_centro_costo, ORG08_CS_COSTO.c_centro_costo FROM LIQ19_EJECUCIONES, LIQ25_PERSONAL_LIQ, PER02_PERSONAL_EMP, LIQ99_LIQUIDACION, LIQ99_RECIBOS, LIQ20_TOT_LIQ_PER, LIQ97_PERSONAL_EMP, PER06_OBRAS_SOC, ORG18_CATEGORIAS, ORG18_CONVENIOS, LIQ01_TIPOS_LIQ, ORG08_CS_COSTO, ORG03_EMPRESAS, ORG03_UBICACIONES JOIN LIQ25_PERSONAL_LIQ.oi_liquidacion INNER LIQ19_EJECUCIONES.oi_liquidacion, LIQ25_PERSONAL_LIQ.oi_personal_emp INNER PER02_PERSONAL_EMP.oi_personal_emp, LIQ99_RECIBOS.oi_liquidacion_ddo INNER LIQ99_LIQUIDACION.oi_liquidacion_ddo, LIQ99_RECIBOS.oi_tot_liq_per INNER LIQ20_TOT_LIQ_PER.oi_tot_liq_per, LIQ99_LIQUIDACION.oi_liquidacion_ddo INNER LIQ19_EJECUCIONES.oi_liquidacion_ddo, PER02_PERSONAL_EMP.e_numero_legajo INNER LIQ99_RECIBOS.e_numero_legajo, LIQ97_PERSONAL_EMP.oi_per_emp_ddo INNER LIQ20_TOT_LIQ_PER.oi_per_emp_ddo, LIQ97_PERSONAL_EMP.c_categoria_ult INNER ORG18_CATEGORIAS.c_categoria, LIQ97_PERSONAL_EMP.c_centro_costo_ult LEFT OUTER ORG08_CS_COSTO.c_centro_costo, LIQ97_PERSONAL_EMP.c_obra_social LEFT OUTER PER06_OBRAS_SOC.c_obra_social, LIQ97_PERSONAL_EMP.c_convenio INNER ORG18_CONVENIOS.c_convenio, LIQ97_PERSONAL_EMP.c_empresa INNER ORG03_EMPRESAS.c_empresa, ORG18_CONVENIOS.oi_convenio INNER ORG18_CATEGORIAS.oi_convenio, ORG18_CATEGORIAS.oi_convenio INNER ORG18_CONVENIOS.oi_convenio, LIQ99_LIQUIDACION.c_tipo_liq INNER LIQ01_TIPOS_LIQ.c_tipo_liq, LIQ97_PERSONAL_EMP.c_ubicacion INNER ORG03_UBICACIONES.c_ubicacion
WHERE LIQ19_EJECUCIONES.oi_liquidacion = {#SOURCE:@value} AND PER02_PERSONAL_EMP.oi_personal_emp in ({%= #PARAMIN:@pers %}) AND LIQ99_LIQUIDACION.c_estado = \'F\' AND ORG03_EMPRESAS.oi_empresa = {#PARAMIN:@oi_empresa} AND ORG03_UBICACIONES.oi_empresa = {#PARAMIN:@oi_empresa}
ORDER BY c_liquidacion ASC, oi_tot_liq_per ASC, e_numero_legajo ASC ')/ROWS/ROW
